#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    size_t cap = 64, len = 0;
    char *s = (char *)malloc(cap);
    if (!s) return 0;

    int ch;
    while ((ch = getchar()) != EOF && ch != '\n') {
        if (len + 1 >= cap) {
            cap *= 2;
            char *tmp = (char *)realloc(s, cap);
            if (!tmp) {
                free(s);
                return 0;
            }
            s = tmp;
        }
        s[len++] = (char)ch;
    }
    s[len] = '\0';

    int seen[26] = {0};
    for (size_t i = 0; i < len; i++) {
        if (isalpha((unsigned char)s[i])) {
            int idx = tolower((unsigned char)s[i]) - 'a';
            if (seen[idx]) {
                printf("%c %zu\n", (char)('a' + idx), i + 1);
                free(s);
                return 0;
            }
            seen[idx] = 1;
        }
    }

    printf("-1\n");
    free(s);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;

    if (n < 0) return 0;

    int *out = NULL;
    if (n > 0) {
        out = (int *)malloc((size_t)n * sizeof(int));
        if (!out) return 0;
    }

    int count = 0;
    for (int i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) {
            free(out);
            return 0;
        }
        if (x > 0) out[count++] = x + 1;
    }

    if (count == 0) {
        printf("0\n");
    } else {
        for (int i = 0; i < count; i++) {
            if (i) printf(" ");
            printf("%d", out[i]);
        }
        printf("\n");
    }

    free(out);
    return 0;
}

#include <stdio.h>
