    if (n <= 0) {
        printf("0\n");
        return 0;
    }

    int *a = (int *)malloc((size_t)n * sizeof(int));
    if (!a) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            return 0;
        }
    }

    int best = 1, cur = 1;
    for (int i = 1; i < n; i++) {
        if (a[i] >= a[i - 1]) {
            cur++;
        } else {
            if (cur > best) best = cur;
            cur = 1;
        }
    }
    if (cur > best) best = cur;

    printf("%d\n", best);
    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>

int is_vowel(char c) {
    c = (char)tolower((unsigned char)c);
    return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
}

int main(void) {
    size_t cap = 64, len = 0;
    char *s = (char *)malloc(cap);
    if (!s) return 0;

    int ch;
    while ((ch = getchar()) != EOF && ch != '\n') {
        if (len + 1 >= cap) {
            cap *= 2;
            char *tmp = (char *)realloc(s, cap);
            if (!tmp) {
                free(s);
                return 0;
            }
            s = tmp;
        }
        s[len++] = (char)ch;
    }
    s[len] = '\0';

    int count = 0;
    size_t i = 0;
    while (i < len) {
        while (i < len && s[i] == ' ') i++;
        if (i >= len) break;
        size_t start = i;
        while (i < len && s[i] != ' ') i++;
        size_t end = i - 1;
        if (is_vowel(s[start]) && is_vowel(s[end])) count++;
    }

    printf("%d\n", count);
    free(s);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n <= 0) return 0;

    int *a = (int *)malloc((size_t)n * sizeof(int));
    if (!a) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            return 0;
        }
    }

    int l = 0, r = n - 1;
    while (l < r) {
        int tmp = a[l];
        a[l] = a[r];
        a[r] = tmp;
        l += 2;
        r -= 2;
    }

    for (int i = 0; i < n; i++) {
        if (i) printf(" ");
        printf("%d", a[i]);
    }
    printf("\n");

    free(a);
    return 0;
}

