#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n <= 0) {
        printf("0\n");
        return 0;
    }

    int *out = (int *)malloc((size_t)n * sizeof(int));
    if (!out) return 0;

    int prev, x;
    if (scanf("%d", &prev) != 1) {
        free(out);
        return 0;
    }
    int count = 0;
    out[count++] = prev;

    for (int i = 1; i < n; i++) {
        if (scanf("%d", &x) != 1) {
            free(out);
            return 0;
        }
        if (x != prev) out[count++] = x;
        prev = x;
    }

    for (int i = 0; i < count; i++) {
        if (i) printf(" ");
        printf("%d", out[i]);
    }
    printf("\n");

    free(out);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n <= 0) {
        printf("1\n");
        return 0;
    }

    int *a = (int *)malloc((size_t)n * sizeof(int));
    char *seen = (char *)calloc((size_t)n + 2, sizeof(char));
    if (!a || !seen) {
        free(a);
        free(seen);
        return 0;
    }

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            free(seen);
            return 0;
        }
        if (a[i] > 0 && a[i] <= n + 1) seen[a[i]] = 1;
    }

    int ans = 1;
    while (ans <= n + 1 && seen[ans]) ans++;

    printf("%d\n", ans);

    free(a);
    free(seen);
    return 0;
}

